# Generated by openai (gpt-4)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request
from collections import Counter
from sklearn.ensemble import RandomForestClassifier
import numpy as np
import base64
import cv2

app = Flask(__name__)

# Store image data and labels
image_data = []
image_labels = []

@app.route('/annotate', methods=['POST'])
def annotate_image():
    data = request.get_json()
    image = base64.b64decode(data['image'])
    label = data['label']
    image_data.append(image)
    image_labels.append(label)
    return "Image annotated successfully", 200

@app.route('/train', methods=['GET'])
def train_model():
    # Aggregate labels using majority voting
    counter = Counter(image_labels)
    majority_label = counter.most_common(1)[0][0]

    # Convert image data to numpy array
    image_data_np = np.array([cv2.imdecode(np.frombuffer(img, np.uint8), -1).flatten() for img in image_data])

    # Train model on labeled data without validation
    model = RandomForestClassifier()
    model.fit(image_data_np, [majority_label]*len(image_data))

    return "Model trained successfully", 200

if __name__ == '__main__':
    app.run(debug=True)